import string

ALPH = string.ascii_uppercase

def clean(s):
    return ''.join(c for c in s.upper() if c.isalpha())

# Vigenere -------------------------------------------------
def vigenere_encrypt(text, key):
    text, key = clean(text), clean(key)
    out = []
    for i, ch in enumerate(text):
        out.append(chr((ord(ch) - 65 + ord(key[i % len(key)]) - 65) % 26 + 65))
    return ''.join(out)

def vigenere_decrypt(text, key):
    text, key = clean(text), clean(key)
    out = []
    for i, ch in enumerate(text):
        out.append(chr((ord(ch) - 65 - (ord(key[i % len(key)]) - 65)) % 26 + 65))
    return ''.join(out)

# Playfair -------------------------------------------------
def playfair_square(key):
    letters = []
    for ch in clean(key).replace('J', 'I') + 'ABCDEFGHIKLMNOPQRSTUVWXYZ':
        if ch not in letters:
            letters.append(ch)
    return [letters[i:i + 5] for i in range(0, 25, 5)]

def pf_pos(square, ch):
    ch = 'I' if ch == 'J' else ch
    for r in range(5):
        for c in range(5):
            if square[r][c] == ch:
                return r, c
    raise ValueError(ch)

def pf_pairs(text):
    text = clean(text).replace('J', 'I')
    pairs, i = [], 0
    while i < len(text):
        a = text[i]
        b = text[i + 1] if i + 1 < len(text) else 'X'
        if a == b:
            pairs.append((a, 'X'))
            i += 1
        else:
            pairs.append((a, b))
            i += 2
    return pairs

def playfair_encrypt(text, key):
    sq = playfair_square(key)
    out = []
    for a, b in pf_pairs(text):
        r1, c1 = pf_pos(sq, a); r2, c2 = pf_pos(sq, b)
        if r1 == r2:
            out += [sq[r1][(c1 + 1) % 5], sq[r2][(c2 + 1) % 5]]
        elif c1 == c2:
            out += [sq[(r1 + 1) % 5][c1], sq[(r2 + 1) % 5][c2]]
        else:
            out += [sq[r1][c2], sq[r2][c1]]
    return ''.join(out)

def playfair_decrypt(text, key):
    sq = playfair_square(key)
    chars = clean(text)
    out = []
    for a, b in zip(chars[0::2], chars[1::2]):
        r1, c1 = pf_pos(sq, a); r2, c2 = pf_pos(sq, b)
        if r1 == r2:
            out += [sq[r1][(c1 - 1) % 5], sq[r2][(c2 - 1) % 5]]
        elif c1 == c2:
            out += [sq[(r1 - 1) % 5][c1], sq[(r2 - 1) % 5][c2]]
        else:
            out += [sq[r1][c2], sq[r2][c1]]
    return ''.join(out)

# ADFGX ----------------------------------------------------
ADFGX = 'ADFGX'
SQUARE25 = 'PHQGIUMEAYLNOFDXKRCVSTZWB'

def adfgx_sub_encrypt(text):
    out = []
    for ch in clean(text).replace('J', 'I'):
        i = SQUARE25.index(ch)
        out.append(ADFGX[i // 5] + ADFGX[i % 5])
    return ''.join(out)

def adfgx_sub_decrypt(text):
    out = []
    for a, b in zip(text[0::2], text[1::2]):
        out.append(SQUARE25[ADFGX.index(a) * 5 + ADFGX.index(b)])
    return ''.join(out)

def col_order(key):
    return sorted(range(len(key)), key=lambda i: (key[i], i))

def transpose_encrypt(text, key):
    key = clean(key)
    rows = [text[i:i + len(key)] for i in range(0, len(text), len(key))]
    rows[-1] = rows[-1].ljust(len(key), 'X')
    return ''.join(''.join(row[i] for row in rows) for i in col_order(key))

def transpose_decrypt(text, key):
    key = clean(key)
    rows = len(text) // len(key)
    cols = [''] * len(key)
    p = 0
    for i in col_order(key):
        cols[i] = text[p:p + rows]
        p += rows
    return ''.join(cols[c][r] for r in range(rows) for c in range(len(key))).rstrip('X')

def adfgx_encrypt(text, key):
    return transpose_encrypt(adfgx_sub_encrypt(text), key)

def adfgx_decrypt(text, key):
    return adfgx_sub_decrypt(transpose_decrypt(clean(text), key))
