from Crypto.Cipher import AES
from Crypto.Random import get_random_bytes

BS = 16

def pad(data: bytes) -> bytes:
    n = BS - len(data) % BS
    return data + bytes([n]) * n

def unpad(data: bytes) -> bytes:
    n = data[-1]
    if n < 1 or n > BS or data[-n:] != bytes([n]) * n:
        raise ValueError('bad padding')
    return data[:-n]

def xor_block(a: bytes, b: bytes) -> bytes:
    return bytes(x ^ y for x, y in zip(a, b))

# ECB: blocks are independent.
def ecb_encrypt(data: bytes, key: bytes) -> bytes:
    aes = AES.new(key, AES.MODE_ECB)
    data = pad(data)
    return b''.join(aes.encrypt(data[i:i + BS]) for i in range(0, len(data), BS))

def ecb_decrypt(data: bytes, key: bytes) -> bytes:
    aes = AES.new(key, AES.MODE_ECB)
    plain = b''.join(aes.decrypt(data[i:i + BS]) for i in range(0, len(data), BS))
    return unpad(plain)

# CBC: plaintext block XOR previous ciphertext block, then encrypt.
def cbc_encrypt(data: bytes, key: bytes, iv: bytes | None = None) -> tuple[bytes, bytes]:
    iv = iv or get_random_bytes(BS)
    aes = AES.new(key, AES.MODE_ECB)
    prev = iv
    out = []
    data = pad(data)
    for i in range(0, len(data), BS):
        block = data[i:i + BS]
        c = aes.encrypt(xor_block(block, prev))
        out.append(c)
        prev = c
    return iv, b''.join(out)

def cbc_decrypt(cipher: bytes, key: bytes, iv: bytes) -> bytes:
    aes = AES.new(key, AES.MODE_ECB)
    prev = iv
    out = []
    for i in range(0, len(cipher), BS):
        block = cipher[i:i + BS]
        p = xor_block(aes.decrypt(block), prev)
        out.append(p)
        prev = block
    return unpad(b''.join(out))
